+      const payload = makePayload();
+      await adapter.send(payload);
+
+      const deliveries = transport.getDeliveries();
+      expect(deliveries).toHaveLength(1);
+      expect(deliveries[0]?.url).toBe('https://hooks.example.com/notify');
+      expect(deliveries[0]?.body.notificationId).toBe('notif-0001');
+      expect(deliveries[0]?.body.type).toBe('order-confirmation');
+      expect(deliveries[0]?.body.subject).toBe('Order Confirmation: order-1');
+      expect(deliveries[0]?.body.body).toContain('Widget x2');
+      expect(deliveries[0]?.body.createdAt).toBe('2026-01-01T00:00:00.000Z');
+    });
+
+    it('should include metadata in the payload when present', async () => {
+      const payload = makePayload({ metadata: { orderId: 'order-1', priority: 'high' } });
+      await adapter.send(payload);
+
+      const deliveries = transport.getDeliveries();
+      expect(deliveries[0]?.body.metadata).toEqual({ orderId: 'order-1', priority: 'high' });
+    });
+
+    it('should omit metadata when not present', async () => {
+      const payload = makePayload();
+      await adapter.send(payload);
+
+      const deliveries = transport.getDeliveries();
+      expect(deliveries[0]?.body.metadata).toBeUndefined();
+    });
+  });
+
+  describe('URL resolution', () => {
+    it('should resolve https URLs directly', async () => {
+      const payload = makePayload({ recipient: 'https://example.com/hook' });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(transport.getDeliveries()[0]?.url).toBe('https://example.com/hook');
+    });
+
+    it('should resolve http URLs directly', async () => {
+      const payload = makePayload({ recipient: 'http://localhost:3000/hook' });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(transport.getDeliveries()[0]?.url).toBe('http://localhost:3000/hook');
+    });
+
+    it('should fail for non-URL recipients', async () => {
+      const payload = makePayload({ recipient: 'user-123' });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Could not resolve webhook URL');
+      expect(result.error).toContain('user-123');
+      expect(transport.getDeliveries()).toHaveLength(0);
+    });
