/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Features:
 * - Formats NotificationPayload as JSON and POSTs to a target URL.
 * - Configurable HTTP transport for testability (defaults to fetch-based).
 * - URL resolver: resolves recipient identifiers to webhook URLs.
 *
 * Implements NotificationAdapter interface.
 * Adapters handle delivery only — they must NOT subscribe to EventBus directly.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body sent to webhook endpoints.
 */
export interface WebhookPayloadBody {
  notificationId: string;
  type: string;
  subject: string;
  body: string;
  recipient: string;
  metadata?: Record<string, unknown>;
  createdAt: string;
}

/**
 * Transport interface for HTTP delivery.
 * Implement this for real HTTP clients or mock for testing.
 */
export interface WebhookTransport {
  post(url: string, body: WebhookPayloadBody): Promise<{ success: boolean; statusCode?: number; error?: string }>;
}

/**
 * Resolves a recipient identifier to a webhook URL.
 * Returns null if the recipient cannot be resolved.
 */
export type WebhookUrlResolver = (recipient: string) => Promise<string | null>;

/**
 * Configuration for the WebhookAdapter.
 */
export interface WebhookAdapterConfig {
  transport?: WebhookTransport;
  urlResolver?: WebhookUrlResolver;
}

/**
 * In-memory transport for testing — stores posted payloads.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private deliveries: Array<{ url: string; body: WebhookPayloadBody }> = [];

  async post(url: string, body: WebhookPayloadBody): Promise<{ success: boolean; statusCode?: number; error?: string }> {
    this.deliveries.push({ url, body });
    return { success: true, statusCode: 200 };
  }

  getDeliveries(): Array<{ url: string; body: WebhookPayloadBody }> {
    return [...this.deliveries];
  }

  clear(): void {
    this.deliveries = [];
  }
}

/**
 * Default URL resolver — treats the recipient as a URL if it starts with
 * 'http://' or 'https://', otherwise returns null.
 */
const defaultUrlResolver: WebhookUrlResolver = async (recipient: string) => {
  if (recipient.startsWith('http://') || recipient.startsWith('https://')) {
    return recipient;
  }
  return null;
};

/**
 * Formats a NotificationPayload into the JSON body sent to webhooks.
 */
function formatPayload(payload: NotificationPayload): WebhookPayloadBody {
  return {
    notificationId: payload.id,
    type: payload.type,
    subject: payload.subject,
    body: payload.body,
    recipient: payload.recipient,
    metadata: payload.metadata,
    createdAt: payload.createdAt.toISOString(),
  };
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;
  private urlResolver: WebhookUrlResolver;

  constructor(config: WebhookAdapterConfig = {}) {
    this.transport = config.transport ?? new InMemoryWebhookTransport();
    this.urlResolver = config.urlResolver ?? defaultUrlResolver;
  }

  /**
   * Send a notification via webhook POST.
   * 1. Resolves recipient to a webhook URL.
   * 2. Formats the payload as JSON.
   * 3. POSTs via the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const resolvedUrl = await this.urlResolver(payload.recipient);
    if (!resolvedUrl) {
      this.logger.warn(`Could not resolve webhook URL for recipient: ${payload.recipient}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: `Could not resolve webhook URL for recipient: ${payload.recipient}`,
        deliveredAt: new Date(),
      };
    }

    const body = formatPayload(payload);

    this.logger.info(`Posting webhook to ${resolvedUrl}: ${payload.subject}`);

    try {
      const result = await this.transport.post(resolvedUrl, body);

      if (!result.success) {
        this.logger.error(`Webhook delivery failed for ${payload.id}: ${result.error}`);
        return {
          success: false,
          notificationId: payload.id,
          channel: this.channel,
          error: result.error ?? 'Webhook delivery failed',
          deliveredAt: new Date(),
        };
      }

      return {
        success: true,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Webhook transport error for ${payload.id}: ${errorMessage}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get the transport (useful for testing with InMemoryWebhookTransport).
   */
  getTransport(): WebhookTransport {
    return this.transport;
  }
}

export { formatPayload };

