      expect(transport.getDeliveries()).toHaveLength(0);
    });

    it('should use custom URL resolver', async () => {
      const resolver: WebhookUrlResolver = async (recipient) => {
        if (recipient === 'team-ops') return 'https://hooks.example.com/ops';
        return null;
      };

      const adapterWithResolver = new WebhookAdapter({ transport, urlResolver: resolver });
      const payload = makePayload({ recipient: 'team-ops' });
      const result = await adapterWithResolver.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getDeliveries()[0]?.url).toBe('https://hooks.example.com/ops');
    });

    it('should fail when custom resolver returns null', async () => {
      const resolver: WebhookUrlResolver = async () => null;
      const adapterWithResolver = new WebhookAdapter({ transport, urlResolver: resolver });
      const payload = makePayload({ recipient: 'unknown-team' });
      const result = await adapterWithResolver.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve webhook URL');
    });
  });

  describe('transport errors', () => {
    it('should handle transport returning failure', async () => {
      const failingTransport: WebhookTransport = {
        async post(): Promise<{ success: boolean; statusCode?: number; error?: string }> {
          return { success: false, statusCode: 500, error: 'Internal Server Error' };
        },
      };

      const failAdapter = new WebhookAdapter({ transport: failingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Internal Server Error');
    });

    it('should handle transport throwing an exception', async () => {
      const throwingTransport: WebhookTransport = {
        async post(): Promise<{ success: boolean; statusCode?: number; error?: string }> {
          throw new Error('Connection refused');
        },
      };

      const failAdapter = new WebhookAdapter({ transport: throwingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });

    it('should handle non-Error throws', async () => {
      const throwingTransport: WebhookTransport = {
        async post(): Promise<{ success: boolean; statusCode?: number; error?: string }> {
          throw 'string error';
        },
      };

      const failAdapter = new WebhookAdapter({ transport: throwingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('string error');
    });
  });

  describe('getTransport', () => {
    it('should return the configured transport', () => {
      expect(adapter.getTransport()).toBe(transport);
    });

    it('should default to InMemoryWebhookTransport', () => {
      const defaultAdapter = new WebhookAdapter();
      expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemoryWebhookTransport);
    });
  });
});

describe('InMemoryWebhookTransport', () => {
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
  });

  it('should store posted deliveries', async () => {
    const body: WebhookPayloadBody = {
      notificationId: 'notif-1',
      type: 'welcome',
      subject: 'Hello',
      body: 'Welcome!',
      recipient: 'https://hooks.example.com/test',
      createdAt: '2026-01-01T00:00:00.000Z',
    };

    const result = await transport.post('https://hooks.example.com/test', body);
    expect(result.success).toBe(true);
    expect(result.statusCode).toBe(200);
    expect(transport.getDeliveries()).toHaveLength(1);
    expect(transport.getDeliveries()[0]?.url).toBe('https://hooks.example.com/test');
  });

  it('should clear deliveries', async () => {
    const body: WebhookPayloadBody = {
      notificationId: 'notif-1',
      type: 'welcome',
      subject: 'Hello',
      body: 'Welcome!',
      recipient: 'https://hooks.example.com/test',
      createdAt: '2026-01-01T00:00:00.000Z',
    };

    await transport.post('https://hooks.example.com/test', body);
    transport.clear();
    expect(transport.getDeliveries()).toHaveLength(0);
  });
});

describe('formatPayload', () => {
  it('should format NotificationPayload into WebhookPayloadBody', () => {
    const payload = makePayload();
    const body = formatPayload(payload);

    expect(body.notificationId).toBe('notif-0001');
    expect(body.type).toBe('order-confirmation');
    expect(body.subject).toBe('Order Confirmation: order-1');
    expect(body.body).toContain('Widget x2');
    expect(body.recipient).toBe('https://hooks.example.com/notify');
    expect(body.createdAt).toBe('2026-01-01T00:00:00.000Z');
  });

  it('should include metadata when present', () => {
    const payload = makePayload({ metadata: { key: 'value' } });
    const body = formatPayload(payload);
    expect(body.metadata).toEqual({ key: 'value' });
  });
});

